		class RSSUtils {
			constructor() {}
			static getRSSvalue(widths, maxWidth, noNarrow) {
				let n = 0;
				for (let width of widths) n += width;
				let val = 0;
				let narrowMask = 0;
				let elements = widths.length;
				for (let bar = 0; bar < elements - 1; bar++) {
					let elmWidth;
					for (elmWidth = 1, narrowMask |= 1 << bar; elmWidth < widths[bar]; elmWidth++, narrowMask &= ~(1 << bar)) {
						let subVal = RSSUtils.combins(n - elmWidth - 1, elements - bar - 2);
						if (noNarrow && narrowMask === 0 && n - elmWidth - (elements - bar - 1) >= elements - bar - 1) subVal -= RSSUtils.combins(n - elmWidth - (elements - bar), elements - bar - 2);
						if (elements - bar - 1 > 1) {
							let lessVal = 0;
							for (let mxwElement = n - elmWidth - (elements - bar - 2); mxwElement > maxWidth; mxwElement--) lessVal += RSSUtils.combins(n - elmWidth - mxwElement - 1, elements - bar - 3);
							subVal -= lessVal * (elements - 1 - bar);
						} else if (n - elmWidth > maxWidth) subVal--;
						val += subVal;
					}
					n -= elmWidth;
				}
				return val;
			}
			static combins(n, r) {
				let maxDenom;
				let minDenom;
				if (n - r > r) {
					minDenom = r;
					maxDenom = n - r;
				} else {
					minDenom = n - r;
					maxDenom = r;
				}
				let val = 1;
				let j = 1;
				for (let i = n; i > maxDenom; i--) {
					val *= i;
					if (j <= minDenom) {
						val /= j;
						j++;
					}
				}
				while (j <= minDenom) {
					val /= j;
					j++;
				}
				return val;
			}
		}
		class BitArrayBuilder {
			static buildBitArray(pairs) {
				let charNumber = pairs.length * 2 - 1;
				if (pairs[pairs.length - 1].getRightChar() == null) charNumber -= 1;
				let binary = new BitArray(12 * charNumber);
				let accPos = 0;
				let firstValue = pairs[0].getRightChar().getValue();
				for (let i = 11; i >= 0; --i) {
					if ((firstValue & 1 << i) != 0) binary.set(accPos);
					accPos++;
				}
				for (let i = 1; i < pairs.length; ++i) {
					let currentPair = pairs[i];
					let leftValue = currentPair.getLeftChar().getValue();
					for (let j = 11; j >= 0; --j) {
						if ((leftValue & 1 << j) != 0) binary.set(accPos);
						accPos++;
					}
					if (currentPair.getRightChar() != null) {
						let rightValue = currentPair.getRightChar().getValue();
						for (let j = 11; j >= 0; --j) {
							if ((rightValue & 1 << j) != 0) binary.set(accPos);
							accPos++;
						}
					}
				}
				return binary;
			}
		}
