				let currentPosition = initialPosition;
				let remaining = null;
				do {
					let info = this.decodeGeneralPurposeField(currentPosition, remaining);
					let parsedFields = FieldParser.parseFieldsInGeneralPurpose(info.getNewString());
					if (parsedFields != null) buff.append(parsedFields);
					if (info.isRemaining()) remaining = "" + info.getRemainingValue();
					else remaining = null;
					if (currentPosition === info.getNewPosition()) break;
					currentPosition = info.getNewPosition();
				} while (true);
